+    // ==================== Precision Loss Detection Tests ====================
+
+    const F32_MAX_EXACT: i64 = 1 << 24; // 16,777,216
+    const F64_MAX_EXACT: i64 = 1 << 53; // 9,007,199,254,740,992
+
+    #[test]
